+interface ChainSegment {
+  command: string;
+  operator: ";" | "&&" | "||" | "";
+}
+
+function splitPipeline(command: string): string[] {
+  // Split on | but not || and not inside quotes
+  const parts: string[] = [];
+  let current = "";
+  let inSingle = false;
+  let inDouble = false;
+
+  for (let i = 0; i < command.length; i++) {
+    const ch = command[i];
+    if (ch === "'" && !inDouble) { inSingle = !inSingle; current += ch; }
+    else if (ch === '"' && !inSingle) { inDouble = !inDouble; current += ch; }
+    else if (ch === "|" && !inSingle && !inDouble && command[i + 1] !== "|" && (i === 0 || command[i - 1] !== "|")) {
+      parts.push(current);
+      current = "";
+    } else {
+      current += ch;
+    }
+  }
+  if (current) parts.push(current);
+  return parts;
+}
+
+function splitChain(command: string): ChainSegment[] {
+  // Split on &&, ||, ; outside quotes
+  const segments: ChainSegment[] = [];
+  let current = "";
+  let inSingle = false;
+  let inDouble = false;
+  let pendingOp: ChainSegment["operator"] = "";
+
+  for (let i = 0; i < command.length; i++) {
+    const ch = command[i];
+    if (ch === "'" && !inDouble) { inSingle = !inSingle; current += ch; continue; }
+    if (ch === '"' && !inSingle) { inDouble = !inDouble; current += ch; continue; }
+    if (inSingle || inDouble) { current += ch; continue; }
+
+    if (ch === "&" && command[i + 1] === "&") {
+      segments.push({ command: current.trim(), operator: pendingOp });
+      current = "";
+      pendingOp = "&&";
+      i++; // skip second &
+    } else if (ch === "|" && command[i + 1] === "|") {
+      segments.push({ command: current.trim(), operator: pendingOp });
+      current = "";
+      pendingOp = "||";
+      i++; // skip second |
+    } else if (ch === ";") {
+      segments.push({ command: current.trim(), operator: pendingOp });
+      current = "";
+      pendingOp = ";";
+    } else {
+      current += ch;
+    }
+  }
+  if (current.trim()) {
+    segments.push({ command: current.trim(), operator: pendingOp });
+  }
+  return segments;
+}
